code.perVertex:
w= -time*0.4; // direction (0: left; asin(1): top; (+/-)2*asin(1): right; -asin(1): bottom);
X2 = x-0.5; // needed to rotate around center;
Y2 = y-0.5; // (if you add a strong shift, it may appear not turning around the center, but find out yourself);
X1 = sin(w)*X2 -cos(w)*Y2; // these 2 lines first rotate the x/y pane;
Y1 = cos(w)*X2 +sin(w)*Y2;;
x = X1; // so you can use x and y as usually below;
y = Y1;;
rad = sqrt(x*x + y*y)*2; // had to replace rad and ang, because of the translation by -.5,-.5;
ang = atan2(x,y);;
dx1=-0.05*sin(1.15+(rad*2-1)*5)+mid/999; // hey this is your code! ;-);
dy1=-0.05*sin(1.+(ang*2-1)*1);;
dx2 = sin(-w)*dx1 - cos(-w)*dy1; // and finally the dx/dy pane is rotated to match the x/y pane;
dy2 = cos(-w)*dx1 + sin(-w)*dy1;;
dx = dx2;;
dy = dy2;;
zoom=1555+sin(time/20) *150;
